VALUES
  ('promotion-6e2f88c7-moex-00014', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', 'B家中之冷氣機故障，遂與A訂立承攬契約，請A修理冷氣，A令其受僱人D前來修理，D於 檢測冷氣機時，不慎導致冷氣機墜下，砸傷B及路人C。有關當事人間之法律關係，下列敘述何 者錯誤？', '["B對D得請求民法第227條規定之債務不履行責任", "B對A得主張民法第188條規定有關僱用人之侵權行為責任", "C對A得主張民法第188條規定有關僱用人之侵權行為責任", "C對D得主張民法第184條第1項前段規定之侵權行為責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00015', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲將其所有之A屋出租予乙，租期2年。下列敘述何者正確？', '["租賃契約為要物契約", "因不可歸責於承租人乙之事由，致A屋毀損時，甲負擔修繕義務", "甲與乙之A屋租賃契約，應以書面為之。未以書面為之者，無效", "甲與乙之A屋租賃契約，其租期不受20年期限之限制 13540 13740"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00016', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲將A花瓶出賣予乙，價金新臺幣5萬元整，約定3日後提出給付。甲將該A花瓶妥善保存，卻 因第三人丙之過失將A花瓶打碎。下列敘述何者正確？', '["甲免除給付A花瓶之義務", "乙得因A花瓶之滅失，向丙主張侵權行為之損害賠償責任", "乙得向甲主張給付不能之損害賠償責任", "甲得向乙請求讓與乙對丙之侵權行為之損害賠償請求權，此為代償請求權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00017', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲對乙有新臺幣100萬元之債權，將該債權讓與於丙，但甲與丙均未通知乙。嗣後，乙因不知債 權已讓與，故對甲清償，而甲亦受領乙之清償。下列敘述何者正確？', '["乙之債務已消滅", "乙之債務未消滅", "經債權人丙之承認，乙之債務始消滅", "於丙受利益之限度內，乙之債務消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00018', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '17歲之甲，對乙有新臺幣（下同）1,000元之債權，而乙對甲有1,200元之債權，雙方之債務均屆 清償期，甲未得其法定代理人事先允許，向乙表示抵銷。下列敘述何者正確？', '["甲與乙之債權債務關係，於1,000元範圍內消滅", "甲與乙之債權債務關係，因甲抵銷而全部消滅", "甲與乙之債權債務關係，於甲成年後，始消滅", "甲與乙之債權債務關係，並不因甲抵銷而消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00019', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '就甲、乙、丙三人對丁負有連帶債務之情形，下列敘述何者正確？', '["甲向丁表示承認連帶債務存在時，其中斷時效之效力及於乙、丙", "甲對丁給付遲延，其效力亦及於乙、丙", "甲向丁為超過其分擔部分之清償後，甲即脫離連帶債務關係", "甲向丁提起確認連帶債務不存在之訴，而獲勝訴確定判決時，該判決效力及於乙、丙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00020', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於不動產物權登記效力之敘述，何者正確？', '["甲訴請乙履行不動產所有權移轉登記之判決勝訴確定後，依民法第758條有關設權登記規定， 須向地政機關辦理登記完畢，始取得其所有權", "甲將不動產所有權移轉登記予乙，嗣後，甲以該移轉行為係無效，而訴請乙塗銷登記時，乙得 適用登記之推定力而主張自己為所有人", "以所有之意思，占有無主之土地，係非因法律行為而取得不動產物權，不待登記即取得所有權", "不動產共有人間關於共有物之分管約定，係依法律行為而使不動產物權發生變更，非經登記， 不生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00021', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲、乙訂立買賣甲所有電腦之契約時，因甲仍暫時有使用該電腦之需求，乙同意將該電腦貸予甲 繼續使用一段期間。該電腦之所有人為何？', '["甲所有", "乙所有", "甲、乙分別共有", "甲、乙公同共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00022', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '就甲於乙所有之A地設定登記普通地上權後，A地遭丙侵奪之情形，下列敘述何者正確？', '["乙得僅將其對丙之所有物返還請求權讓與第三人", "甲得直接請求丙將受侵奪之A地返還於己", "乙對丙之所有物返還請求權，經15年不行使而消滅", "甲不得對善意無過失之丙請求返還A地於己"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00023', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '為擔保甲對乙之新臺幣（下同）1,000萬元X債權，乙、丙、丁分別提供其各自所有之A、B、C 不動產供甲設定均為第一次序之普通抵押權，其中C設定擔保金額為500萬元。X債權清償期屆 至時，乙無力清償，甲乃實行對上述不動產之抵押權，A、B、C分別拍賣，得款400萬元、500 萬元、300萬元。就各自拍賣所得金額，應如何進行分配（小數點部分四捨五入）？', '["A分配333萬元、B分配417萬元、C分配250萬元", "A分配400萬元、B分配300萬元、C分配300萬元", "A分配400萬元、B分配375萬元、C分配225萬元", "A分配311萬元、B分配389萬元、C分配300萬元 13540 13740"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
